const items = $input.all().map(i => i.json);
const http = this.helpers.httpRequest;
const GKEY = $env.GEMINI_API_KEY;
const MAX = 20;
const STAT = new Set(['À appeler', 'À relancer']);
const confMap = { haute: 'Haute', moyenne: 'Moyenne', faible: 'Faible' };
const todo = items.filter(f => STAT.has((f['Statut Prospection'] || '').toString().trim()) && !((f['LinkedIn URL'] || '').toString().trim())).slice(0, MAX);
const out = [];
for (const f of todo) {
  const id = f.id;
  const prenom = (f['Prénom'] || '').toString().trim();
  const nom = (f['Nom'] || '').toString().trim();
  const full = (prenom + ' ' + nom).trim() || (f['Profile Name'] || '').toString().trim();
  const comp = (f['Company Name'] || '').toString().trim();
  const poste = (f['Poste'] || '').toString().trim();
  if (!id || !full) continue;
  let url = '', conf = 'faible';
  try {
    if (GKEY) {
      const prompt = "Trouve l'URL exacte du profil LinkedIn de cette personne précise.\n" +
        'Nom: ' + full + '\n' + (comp ? ('Entreprise: ' + comp + '\n') : '') + (poste ? ('Poste: ' + poste + '\n') : '') +
        'Cherche sur le web (site:linkedin.com/in). L URL doit commencer par https://www.linkedin.com/in/ ou https://fr.linkedin.com/in/.\n' +
        "Vérifie que l'entreprise et/ou le poste correspondent. Si tu n'es pas certain que ce soit LA bonne personne, mets confiance 'faible'.\n" +
        'Réponds STRICTEMENT en JSON sur une seule ligne, sans aucun texte autour: {"url":"...","confiance":"haute|moyenne|faible"}. Si aucun profil fiable trouvé: {"url":"","confiance":"faible"}.';
      const r = await http({ method: 'POST', url: 'https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash:generateContent?key=' + encodeURIComponent(GKEY), body: { contents: [{ parts: [{ text: prompt }] }], tools: [{ google_search: {} }], generationConfig: { temperature: 0 } }, json: true, timeout: 20000 });
      const parts = (r && r.candidates && r.candidates[0] && r.candidates[0].content && r.candidates[0].content.parts) || [];
      const txt = parts.map(p => p.text || '').join(' ');
      const mj = txt.match(/\{[\s\S]*?\}/);
      if (mj) { try { const o = JSON.parse(mj[0]); url = (o.url || '').toString().trim(); conf = (o.confiance || 'faible').toString().toLowerCase().trim(); } catch (e) {} }
      if (url && !/linkedin\.com\/in\//i.test(url)) { url = ''; conf = 'faible'; }
      if (!url) conf = 'faible';
    }
  } catch (e) {}
  out.push({ json: { id: id, 'LinkedIn URL (proposé)': url, 'Confiance URL': confMap[conf] || 'Faible' } });
}
return out;
